To start a new process in C++ with one file descriptor connected to its input and output, you can use the `fork()` and `dup2()` functions. Here's a simple example:

```cpp
#include <iostream>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>

int main() {
    int pipefd[2];
    pid_t pid;

    // Create a pipe
    if (pipe(pipefd) == -1) {
        perror("pipe");
        return 1;
    }

    // Fork a child process
    pid = fork();
    if (pid == -1) {
        perror("fork");
        return 1;
    } else if (pid > 0) { // Parent process
        // Close the write end of the pipe in the parent
        close(pipefd[1]);

        // Read from the pipe
        char buf[50];
        read(pipefd[0], buf, sizeof(buf));
        std::cout << "Parent received: " << buf << std::endl;

        // Wait for the child to finish
        wait(NULL);
    } else { // Child process
        // Close the read end of the pipe
        close(pipefd[0]);

        // Duplicate the pipe write end to standard output
        dup2(pipefd[1], STDOUT_FILENO);

        // Close the pipe write end
        close(pipefd[1]);

        // Print something to the child's stdout, which is now connected to the pipe
        std::cout << "Hello from the child!" << std::endl;

        // Exit the child process
        _exit(0);
    }

    return 0;
}
```

This code creates a pipe, forks a child process, and connects the child's standard output to the write end of the pipe. The parent then reads from the pipe to receive the output from the child.
